            { label: '외부 요인', content: '마감 일정 압박, 팀원과 다른 의견과 그로 인한 의견 충돌', color: '#F53102' },
            { label: '내부 요인', content: '갈등을 해결하려하지 않고 회피하려는 심리, 혼자서도 다 해결할 수 있다는 과신', color: '#0075FF' }
